INSERT INTO "AiChatLog" ("id", "userId", "projectId", "prompt", "response", "moduleContext", "modelVersion", "rating", "tokensUsed", "createdAt") VALUES ('ai-001', 'usr-009', 'prj-001', 'Bagaimana cara mengira beban penyejukan untuk bilik 20m²?', 'Untuk mengira beban penyejukan bilik 20m², anda perlu mempertimbangkan: (1) Beban haba sensibel dari dinding, siling dan lantai (~100-150 W/m²), (2) Beban haba dalaman dari penghuni (~80W/orang), (3) Beban peralatan elektrik, (4) Beban solaran melalui tingkap. Anggaran kasar: 20m² × 150W/m² = 3000W ≈ 1 HP. Cadangan: gunakan BTU/hr = 20m² × 1000 BTU/hr/m² = 20,000 BTU/hr ≈ 1.7 HP. Sila rujuk ASHRAE Fundamentals untuk pengiraan terperinci.', 'technical_qa', 'glm-4.6', 5, 150, '2026-07-14T09:40:58.628Z');
INSERT INTO "AiChatLog" ("id", "userId", "projectId", "prompt", "response", "moduleContext", "modelVersion", "rating", "tokensUsed", "createdAt") VALUES ('ai-002', 'usr-010', 'prj-002', 'Apakah perbezaan antara litar pemula DOL dan Star-Delta untuk motor 3 fasa?', 'Pemula DOL (Direct-On-Line) menyambung motor terus ke bekalan penuh, menghasilkan arus mula yang tinggi (6-8 kali arus nominal) tetapi tork mula penuh. Sesuai untuk motor kecil (<5HP). Pemula Star-Delta memulakan motor dalam sambungan Star (voltan dikurangkan √3 kali, arus dan tork dikurangkan 1/3) kemudian bertukar ke Delta selepas motor mencapai kelajuan. Sesuai untuk motor besar (>5HP) di mana arus mula perlu dikawal. Trade-off: Star-Delta mengurangkan tork mula, jadi tidak sesuai untuk beban yang memerlukan tork mula tinggi seperti pam.', 'technical_qa', 'glm-4.6', NULL, 157, '2026-07-14T03:40:58.630Z');
INSERT INTO "AiChatLog" ("id", "userId", "projectId", "prompt", "response", "moduleContext", "modelVersion", "rating", "tokensUsed", "createdAt") VALUES ('ai-003', 'usr-011', 'prj-003', 'Apakah piawaian keselamatan elektrik yang perlu dipatuhi di Malaysia?', 'Piawaian keselamatan elektrik utama di Malaysia: (1) MS IEC 60364 - Pemasangan elektrik bangunan, (2) MS IEC 60947 - Peralatan kawalan voltan rendah, (3) Akta Bekalan Elektrik 1990 & Peraturan-peraturan Elektrik 1994, (4) Garis Panduan Suruhanjaya Tenaga. Amalan utama: gunakan PPE (sarung tangan isolasi, kasut getah), pastikan pembumian baik (<5Ω), labelkan panel dengan jelas, lakukan ujian isolasi berkala, dan sentiasa kunci tag (LOTO) sekerja pada litar.', 'technical_qa', 'glm-4.6', NULL, 164, '2026-07-13T21:40:58.631Z');
INSERT INTO "AiChatLog" ("id", "userId", "projectId", "prompt", "response", "moduleContext", "modelVersion", "rating", "tokensUsed", "createdAt") VALUES ('ai-004', 'usr-012', 'prj-004', 'Bantu saya tulis objektif untuk projek sistem kawalan motor PLC', 'Cadangan objektif projek: 1) Merekabentuk sistem kawalan motor 3 fasa berasaskan PLC Siemens S7-1200 dengan fungsi start-stop, reverse dan perlindungan beban lebih. 2) Membina panel kawalan lengkap dengan pendawaian mengikut MS IEC 60364. 3) Membangunkan aturcara ladder logic untuk automasi operasi motor. 4) Menjalankan ujian fungsi dan prestasi sistem termasuk ujian arus mula dan tork. 5) Mendokumentasikan laporan teknikal lengkap dengan gambarajah litar, senarai BOM, dan analisis keputusan ujian.', 'proposal_help', 'glm-4.6', 4, 171, '2026-07-13T15:40:58.633Z');
INSERT INTO "AiChatLog" ("id", "userId", "projectId", "prompt", "response", "moduleContext", "modelVersion", "rating", "tokensUsed", "createdAt") VALUES ('ai-005', 'usr-013', 'prj-005', 'Ringkaskan kemajuan pelajar saya minggu ini', 'Berdasarkan log mingguan terkini, pelajar telah menyiapkan pembinaan prototaip dan sedang dalam fasa ujian fungsi. Isu utama: pemanasan berlebihan pada transistor kawalan telah diselesaikan dengan penambahan heatsink. Jumlah jam kerja minggu ini: 8 jam. Status: SIGNED_OFF. Cadangan: pelajar perlu mula menyediakan dokumentasi laporan sambil menunggu keputusan ujian akhir.', 'logbook_review', 'glm-4.6', NULL, 178, '2026-07-13T09:40:58.634Z');
INSERT INTO "AiChatLog" ("id", "userId", "projectId", "prompt", "response", "moduleContext", "modelVersion", "rating", "tokensUsed", "createdAt") VALUES ('ai-006', 'usr-014', 'prj-006', 'Jana maklum balas untuk markah rubrik: analisis_teknikal=15, reka_bentuk=20', 'Maklum balas (draf): Analisis teknikal (15/20) - Analisis teknikal menunjukkan pemahaman yang baik tentang prinsip asas, namun bahasan terhadap pertimbangan alternatif boleh diperkukuh. Reka bentuk sistem (20/25) - Reka bentuk sistem adalah menyeluruh dan pelaksanaan praktikal. Beberapa penambahbaikan pada pemilihan komponen untuk mengoptimumkan kos disarankan. Secara keseluruhan, kemajuan projek adalah memuaskan dengan potensi peningkatan dalam dokumentasi justifikasi reka bentuk.', 'feedback_draft', 'glm-4.6', 5, 185, '2026-07-13T03:40:58.635Z');
