INSERT INTO "AiChatLog" ("id", "userId", "projectId", "prompt", "response", "moduleContext", "modelVersion", "rating", "tokensUsed", "createdAt") VALUES ('ai-017', 'usr-025', 'prj-017', 'Ringkaskan kemajuan pelajar saya minggu ini', 'Berdasarkan log mingguan terkini, pelajar telah menyiapkan pembinaan prototaip dan sedang dalam fasa ujian fungsi. Isu utama: pemanasan berlebihan pada transistor kawalan telah diselesaikan dengan penambahan heatsink. Jumlah jam kerja minggu ini: 8 jam. Status: SIGNED_OFF. Cadangan: pelajar perlu mula menyediakan dokumentasi laporan sambil menunggu keputusan ujian akhir.', 'logbook_review', 'glm-4.6', NULL, 262, '2026-07-10T09:40:58.652Z');
INSERT INTO "AiChatLog" ("id", "userId", "projectId", "prompt", "response", "moduleContext", "modelVersion", "rating", "tokensUsed", "createdAt") VALUES ('ai-018', 'usr-026', 'prj-018', 'Jana maklum balas untuk markah rubrik: analisis_teknikal=15, reka_bentuk=20', 'Maklum balas (draf): Analisis teknikal (15/20) - Analisis teknikal menunjukkan pemahaman yang baik tentang prinsip asas, namun bahasan terhadap pertimbangan alternatif boleh diperkukuh. Reka bentuk sistem (20/25) - Reka bentuk sistem adalah menyeluruh dan pelaksanaan praktikal. Beberapa penambahbaikan pada pemilihan komponen untuk mengoptimumkan kos disarankan. Secara keseluruhan, kemajuan projek adalah memuaskan dengan potensi peningkatan dalam dokumentasi justifikasi reka bentuk.', 'feedback_draft', 'glm-4.6', NULL, 269, '2026-07-10T03:40:58.654Z');
INSERT INTO "AiChatLog" ("id", "userId", "projectId", "prompt", "response", "moduleContext", "modelVersion", "rating", "tokensUsed", "createdAt") VALUES ('ai-019', 'usr-027', 'prj-019', 'Bagaimana cara mengira beban penyejukan untuk bilik 20m²?', 'Untuk mengira beban penyejukan bilik 20m², anda perlu mempertimbangkan: (1) Beban haba sensibel dari dinding, siling dan lantai (~100-150 W/m²), (2) Beban haba dalaman dari penghuni (~80W/orang), (3) Beban peralatan elektrik, (4) Beban solaran melalui tingkap. Anggaran kasar: 20m² × 150W/m² = 3000W ≈ 1 HP. Cadangan: gunakan BTU/hr = 20m² × 1000 BTU/hr/m² = 20,000 BTU/hr ≈ 1.7 HP. Sila rujuk ASHRAE Fundamentals untuk pengiraan terperinci.', 'technical_qa', 'glm-4.6', 4, 276, '2026-07-09T21:40:58.655Z');
INSERT INTO "AiChatLog" ("id", "userId", "projectId", "prompt", "response", "moduleContext", "modelVersion", "rating", "tokensUsed", "createdAt") VALUES ('ai-020', 'usr-028', 'prj-020', 'Apakah perbezaan antara litar pemula DOL dan Star-Delta untuk motor 3 fasa?', 'Pemula DOL (Direct-On-Line) menyambung motor terus ke bekalan penuh, menghasilkan arus mula yang tinggi (6-8 kali arus nominal) tetapi tork mula penuh. Sesuai untuk motor kecil (<5HP). Pemula Star-Delta memulakan motor dalam sambungan Star (voltan dikurangkan √3 kali, arus dan tork dikurangkan 1/3) kemudian bertukar ke Delta selepas motor mencapai kelajuan. Sesuai untuk motor besar (>5HP) di mana arus mula perlu dikawal. Trade-off: Star-Delta mengurangkan tork mula, jadi tidak sesuai untuk beban yang memerlukan tork mula tinggi seperti pam.', 'technical_qa', 'glm-4.6', NULL, 283, '2026-07-09T15:40:58.656Z');
INSERT INTO "AiChatLog" ("id", "userId", "projectId", "prompt", "response", "moduleContext", "modelVersion", "rating", "tokensUsed", "createdAt") VALUES ('ai-021', 'usr-029', 'prj-021', 'Apakah piawaian keselamatan elektrik yang perlu dipatuhi di Malaysia?', 'Piawaian keselamatan elektrik utama di Malaysia: (1) MS IEC 60364 - Pemasangan elektrik bangunan, (2) MS IEC 60947 - Peralatan kawalan voltan rendah, (3) Akta Bekalan Elektrik 1990 & Peraturan-peraturan Elektrik 1994, (4) Garis Panduan Suruhanjaya Tenaga. Amalan utama: gunakan PPE (sarung tangan isolasi, kasut getah), pastikan pembumian baik (<5Ω), labelkan panel dengan jelas, lakukan ujian isolasi berkala, dan sentiasa kunci tag (LOTO) sekerja pada litar.', 'technical_qa', 'glm-4.6', 5, 290, '2026-07-09T09:40:58.658Z');
