INSERT INTO "AiChatLog" ("id", "userId", "projectId", "prompt", "response", "moduleContext", "modelVersion", "rating", "tokensUsed", "createdAt") VALUES ('ai-042', 'usr-025', 'prj-017', 'Jana maklum balas untuk markah rubrik: analisis_teknikal=15, reka_bentuk=20', 'Maklum balas (draf): Analisis teknikal (15/20) - Analisis teknikal menunjukkan pemahaman yang baik tentang prinsip asas, namun bahasan terhadap pertimbangan alternatif boleh diperkukuh. Reka bentuk sistem (20/25) - Reka bentuk sistem adalah menyeluruh dan pelaksanaan praktikal. Beberapa penambahbaikan pada pemilihan komponen untuk mengoptimumkan kos disarankan. Secara keseluruhan, kemajuan projek adalah memuaskan dengan potensi peningkatan dalam dokumentasi justifikasi reka bentuk.', 'feedback_draft', 'glm-4.6', NULL, 437, '2026-07-04T03:40:58.714Z');
INSERT INTO "AiChatLog" ("id", "userId", "projectId", "prompt", "response", "moduleContext", "modelVersion", "rating", "tokensUsed", "createdAt") VALUES ('ai-043', 'usr-026', 'prj-018', 'Bagaimana cara mengira beban penyejukan untuk bilik 20m²?', 'Untuk mengira beban penyejukan bilik 20m², anda perlu mempertimbangkan: (1) Beban haba sensibel dari dinding, siling dan lantai (~100-150 W/m²), (2) Beban haba dalaman dari penghuni (~80W/orang), (3) Beban peralatan elektrik, (4) Beban solaran melalui tingkap. Anggaran kasar: 20m² × 150W/m² = 3000W ≈ 1 HP. Cadangan: gunakan BTU/hr = 20m² × 1000 BTU/hr/m² = 20,000 BTU/hr ≈ 1.7 HP. Sila rujuk ASHRAE Fundamentals untuk pengiraan terperinci.', 'technical_qa', 'glm-4.6', 4, 444, '2026-07-03T21:40:58.716Z');
INSERT INTO "AiChatLog" ("id", "userId", "projectId", "prompt", "response", "moduleContext", "modelVersion", "rating", "tokensUsed", "createdAt") VALUES ('ai-044', 'usr-027', 'prj-019', 'Apakah perbezaan antara litar pemula DOL dan Star-Delta untuk motor 3 fasa?', 'Pemula DOL (Direct-On-Line) menyambung motor terus ke bekalan penuh, menghasilkan arus mula yang tinggi (6-8 kali arus nominal) tetapi tork mula penuh. Sesuai untuk motor kecil (<5HP). Pemula Star-Delta memulakan motor dalam sambungan Star (voltan dikurangkan √3 kali, arus dan tork dikurangkan 1/3) kemudian bertukar ke Delta selepas motor mencapai kelajuan. Sesuai untuk motor besar (>5HP) di mana arus mula perlu dikawal. Trade-off: Star-Delta mengurangkan tork mula, jadi tidak sesuai untuk beban yang memerlukan tork mula tinggi seperti pam.', 'technical_qa', 'glm-4.6', NULL, 151, '2026-07-03T15:40:58.717Z');
INSERT INTO "AiChatLog" ("id", "userId", "projectId", "prompt", "response", "moduleContext", "modelVersion", "rating", "tokensUsed", "createdAt") VALUES ('ai-045', 'usr-028', 'prj-020', 'Apakah piawaian keselamatan elektrik yang perlu dipatuhi di Malaysia?', 'Piawaian keselamatan elektrik utama di Malaysia: (1) MS IEC 60364 - Pemasangan elektrik bangunan, (2) MS IEC 60947 - Peralatan kawalan voltan rendah, (3) Akta Bekalan Elektrik 1990 & Peraturan-peraturan Elektrik 1994, (4) Garis Panduan Suruhanjaya Tenaga. Amalan utama: gunakan PPE (sarung tangan isolasi, kasut getah), pastikan pembumian baik (<5Ω), labelkan panel dengan jelas, lakukan ujian isolasi berkala, dan sentiasa kunci tag (LOTO) sekerja pada litar.', 'technical_qa', 'glm-4.6', NULL, 158, '2026-07-03T09:40:58.720Z');
INSERT INTO "AiChatLog" ("id", "userId", "projectId", "prompt", "response", "moduleContext", "modelVersion", "rating", "tokensUsed", "createdAt") VALUES ('ai-046', 'usr-029', 'prj-021', 'Bantu saya tulis objektif untuk projek sistem kawalan motor PLC', 'Cadangan objektif projek: 1) Merekabentuk sistem kawalan motor 3 fasa berasaskan PLC Siemens S7-1200 dengan fungsi start-stop, reverse dan perlindungan beban lebih. 2) Membina panel kawalan lengkap dengan pendawaian mengikut MS IEC 60364. 3) Membangunkan aturcara ladder logic untuk automasi operasi motor. 4) Menjalankan ujian fungsi dan prestasi sistem termasuk ujian arus mula dan tork. 5) Mendokumentasikan laporan teknikal lengkap dengan gambarajah litar, senarai BOM, dan analisis keputusan ujian.', 'proposal_help', 'glm-4.6', 5, 165, '2026-07-03T03:40:58.721Z');
